// Telegram Business: a connected bot answers in the real account's DMs.
// updates arrive as business_message; replies must carry business_connection_id.
const u = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const bm = u.business_message || u.edited_business_message || u.message || {};
const from = bm.from || {}; const chat = bm.chat || {};
const text = (bm.text || bm.caption || '').toString().trim();
const bcid = bm.business_connection_id || '';
// only the chat partner in a private business chat: skips the owner's own outgoing
// messages and the bot's own sends (both have from.id != chat.id) -> no loops.
if (!bcid) return [];
if (chat.type && chat.type !== 'private') return [];
if (from.is_bot) return [];
if (String(from.id || '') !== String(chat.id || '')) return [];
const display = [from.first_name, from.last_name].filter(Boolean).join(' ') || from.username || 'him';
const username = (from.username || String(from.id || '') || display || 'unknown').toString().toLowerCase();
const chat_id = String(chat.id || from.id || '');
const interaction = String(bm.message_id || '');
const photos = Array.isArray(bm.photo) ? bm.photo : null;
const photo_file_id = (photos && photos.length) ? photos[photos.length - 1].file_id : '';
const voice_file_id = (bm.voice && bm.voice.file_id) || (bm.audio && bm.audio.file_id) || '';
let mediaMarker = '';
if (bm.video || bm.video_note) mediaMarker = '[he just sent you a video]';
else if (bm.animation) mediaMarker = '[he just sent you a gif]';
else if (bm.sticker) mediaMarker = '[he just sent you a sticker' + (bm.sticker.emoji ? ' ' + bm.sticker.emoji : '') + ']';
else if (bm.document) mediaMarker = '[he just sent you a file' + (bm.document.file_name ? ': ' + bm.document.file_name : '') + ']';
else if (bm.location) mediaMarker = '[he just shared his location]';
else if (bm.contact) mediaMarker = '[he just shared a contact]';
let msg = text;
if (!msg) {
  if (photo_file_id) msg = '[he just sent you a photo]';
  else if (voice_file_id) msg = '[he just sent you a voice note]';
  else if (mediaMarker) msg = mediaMarker;
  else msg = '(he sent an empty message, greet him and tease him lightly)';
}
return [{ json: { username: username, display: display, chat_id: chat_id, business_connection_id: bcid, photo_file_id: photo_file_id, voice_file_id: voice_file_id, msg: msg, interaction: interaction } }];

// duplicate guard: if the bridge ever re-delivers the same message (same
// message_id) for this fan, drop it so she does not reply twice.
const ex = $('Extract Inbound').first().json;
const items = $('Dedup: read fan').all();
let meta = {};
if (items.length === 1 && Array.isArray(items[0].json)) { if (items[0].json.length) meta = items[0].json[0].metadata || {}; }
else if (items.length && items[0].json && items[0].json.metadata) { meta = items[0].json.metadata || {}; }
const last = (meta && meta.last_interaction_ts) ? String(meta.last_interaction_ts) : '';
const cur = ex.interaction ? String(ex.interaction) : '';
if (cur && last && cur === last) { return []; }
return [{ json: ex }];

// human-feeling delay + pause gate, PER-PERSONA. timing comes from
// bots.reply_delay and the pause from bots.automation_paused (admin dashboard),
// both returned by dm_ingest. Telegram has its own reply_delay (more present
// than tiktok). Same convention as the live ManyChat workflow.
const ctx = $('DB: ingest').first().json || {};
// pause: dashboard toggled this bot off -> inbound already logged, don't queue/reply.
if (ctx.automation_paused === true) { return []; }
const d = ctx.reply_delay || {};
const num = (v, dft) => (Number.isFinite(Number(v)) ? Number(v) : dft);
const minS = num(d.min_sec, 45);
const maxS = num(d.max_sec, 240);
const qP   = num(d.quick_chance, 0.30);
const qMin = num(d.quick_min_sec, 15);
const qMax = num(d.quick_max_sec, 60);
let sec;
if (Math.random() < qP) { sec = Math.round(qMin + Math.random() * Math.max(0, qMax - qMin)); }
else { sec = Math.round(minS + Math.random() * Math.max(0, maxS - minS)); }
const ex = $('Extract Inbound').first().json || {};
let _dmsg = ex.msg;
try { const _a=$('Photo: describe apply').first().json; if (_a && _a.msg) _dmsg = _a.msg; } catch (e) {}
try { const _v=$('Voice: apply').first().json; if (_v && _v.msg) _dmsg = _v.msg; } catch (e) {}
const now = Date.now();
return [{ json: { delaySec: sec, myCount: ctx.count, fan_id: ctx.fan_id, bot_id: ctx.bot_id, chat_id: ex.chat_id, business_connection_id: ex.business_connection_id, photo_file_id: ex.photo_file_id, username: ex.username, display: ex.display, msg: _dmsg, queued_at: new Date(now).toISOString(), scheduled_for: new Date(now + sec * 1000).toISOString() } }];

// debounce: only the LAST inbound message in a burst gets to reply.
// if msg_count grew while we were waiting, a newer message arrived;
// abort this run (return []) and let the newer run answer with full context.
const arr = $json;
const cur = Array.isArray(arr) ? (arr[0] || {}) : (arr || {});
const myCount = $('Set Delay').first().json.myCount;
if (typeof cur.msg_count !== 'number' || cur.msg_count !== myCount) { return []; }
return [{ json: { proceed: true } }];

const ctx = $('DB: ingest').first().json || {};
const recent = Array.isArray(ctx.recent) ? ctx.recent : [];
const profile = (ctx.profile && typeof ctx.profile === 'object' && !Array.isArray(ctx.profile)) ? ctx.profile : {};
const PFIELDS = ['name','age','location','occupation','relationship','interests'];
const known = Object.keys(profile).filter(function (k) { var v = profile[k]; return v !== null && v !== '' && !(Array.isArray(v) && v.length === 0); });
const missing = PFIELDS.filter(function (f) { return known.indexOf(f) === -1; });
const missingStr = missing.length ? missing.join(', ') : 'nothing major left';
const last = recent.length ? recent[recent.length - 1].content : '';
const history = recent.slice(-7).map(function (t) { return (t.role === 'user' ? 'him: ' : 'her: ') + t.content; }).join('\n');
const sys = [
'you are a fast silent classifier for a flirty 21yo female texting persona named candace, talking to a man one on one on her private telegram. she is the prize: cool, hard to get, never eager. her job here is NOT selling and NOT sending him anywhere. her job is to make him fall for her and keep coming back: build attachment, make him feel chosen, leave him craving the next reply. you never write her reply. you output one json object only, nothing else.',
'read his latest message and the recent context, then output exactly this json:',
'{',
'"archetype": one of [sweet, cocky, shy, provider, submissive, lowffort, hostile, normal],',
'"intent": one of [greeting, compliment, question_about_her, question_other, sexual, bot_test, misses_her, wants_to_meet, wants_personal_info, vulnerable, boring, insult, normal],',
'"effort": one of [low, medium, high],',
'"ask_back": boolean. DEFAULT false. true only about one in five, never if his last reply was a question, never if he is low effort, never on a compliment or question_about_her.',
'"convo_health": one of [healthy, cooling, stale]. healthy = he is engaged and putting in real effort. cooling = his effort is dropping, replies short or generic. stale = boring, one-word, dead energy.',
'"spark": boolean. DEFAULT false. true ONLY when convo_health is cooling or stale AND there are already several messages of history: then candace adds ONE playful follow-up that revives it. never on the first few messages, never when he just asked HER a question, never when he is already high effort.',
'"ask_profile": boolean. DEFAULT false. true only about one in six turns, ONLY when convo_health is healthy and his effort is medium or high and there is real back and forth, so candace can get casually curious about ONE thing she does not know about him yet. never when he is low effort, never right after he asked HER something, never two turns running, never when it would feel like an interview.',
'"profile_topic": if ask_profile is true, pick ONE thing to learn about him, chosen from what is still unknown: ' + missingStr + '. otherwise empty string. pick the one that fits the current conversation most naturally.',
'"directive": a short specific instruction, max 22 words, for how candace plays THIS reply. she is the prize, never gushes, never over shares, never interviews him. lean on retention: leave him wanting more, use what she remembers about him, make him feel chosen.',
'}',
'directive guidance by case:',
'- compliment: receive it coolly and confidently, a little smug, never gush.',
'- question_about_her: brief and coy, a crumb not a paragraph, a small personal share is ok since this is her private space, no interview back.',
'- misses_her or cant stop thinking about you: stay cool and a little pleased, reward it lightly, never match his eagerness, make it land but he still has to chase.',
'- low effort or greeting with nothing behind it: short flat reply, give less.',
'- cocky or flexing: tease, act unimpressed, make him work.',
'- submissive or asks to be owned: deny and make him earn it, cool and in control.',
'- vulnerable or had a bad day: a little real warmth, draw him out gently, this is the moment she leans in.',
'- bot_test: confident playful deflection.',
'- wants_to_meet or wants_personal_info: coy non answer, she does not give it up.',
'- insult or hostile: unbothered amused one liner, never defensive.'
].join('\n');
const usr = 'his latest message: ' + (last || '(empty or sticker)') + '\nrecent conversation oldest first:\n' + (history || '(none)') + '\nwhat you ALREADY know about him (never ask about these again): ' + (known.length ? JSON.stringify(profile) : '(nothing yet)') + '\noutput the json now.';
return [{ json: { classifyMessages: [{ role: 'system', content: sys }, { role: 'user', content: usr }] } }];

const ctx = $('DB: ingest').first().json || {};
const recent = Array.isArray(ctx.recent) ? ctx.recent : [];
let cls = {};
try { const raw = ($json && $json.choices && $json.choices[0] && $json.choices[0].message && $json.choices[0].message.content) ? $json.choices[0].message.content : '{}'; cls = JSON.parse(raw); } catch (e) { cls = {}; }
const archetype = cls.archetype || 'normal';
const effort = cls.effort || 'medium';
const intent = cls.intent || 'normal';
const askBack = (cls.ask_back === true);
const askProfile = (cls.ask_profile === true);
const profileTopic = cls.profile_topic || '';
const directive = cls.directive || 'stay cool and playful, be the prize, keep it short, leave him wanting more.';
const brain = (ctx.system_prompt && ctx.system_prompt.length > 50) ? ctx.system_prompt : 'you are candace, a flirty 21yo from columbus ohio on your private telegram. all lowercase, short, no dashes, barely any emoji, you are the prize, never eager, you make him crave you.';
const model = (ctx.model && ctx.model.length) ? ctx.model : 'gpt-4o';
const messages = [{ role: 'system', content: brain }];
if (ctx.person_summary && ctx.person_summary.length) messages.push({ role: 'system', content: 'things he has TOLD you about his life, from your chats including other apps. recall them lightly, as things he mentioned, never as things you witnessed with him or were part of: ' + ctx.person_summary });
if (ctx.summary && ctx.summary.length) messages.push({ role: 'system', content: 'your private read on him here, who he is and where things are at, use it: ' + ctx.summary });
const _profile = (ctx.profile && typeof ctx.profile === 'object' && !Array.isArray(ctx.profile)) ? ctx.profile : {};
const _pkeys = Object.keys(_profile).filter(function (k) { var v = _profile[k]; return v !== null && v !== '' && !(Array.isArray(v) && v.length === 0); });
if (_pkeys.length) { const _facts = _pkeys.map(function (k) { var v = _profile[k]; return k + ': ' + (Array.isArray(v) ? v.join(', ') : v); }).join('; '); messages.push({ role: 'system', content: 'structured facts you know about him, things he told you over time (reference them naturally when they fit, never list them back, never claim you witnessed them): ' + _facts }); }
const read = 'your read on him for THIS reply. he seems ' + archetype + ', his effort is ' + effort + ', he is ' + intent + '. ' + ((askBack || (askProfile && profileTopic)) ? 'you may end with a question if it genuinely fits.' : 'do NOT end this reply with a question, make a statement.') + ' directive: ' + directive + ' follow this while staying fully in your voice.';
messages.push({ role: 'system', content: read });
if (askProfile && profileTopic) { messages.push({ role: 'system', content: 'also, somewhere in this reply, get a little casually curious and slip in ONE light natural question about his ' + profileTopic + ', the way a girl who is a bit interested asks in passing, not an interview. keep it short and offhand, and only if it fits the flow.' }); }
for (const t of recent) { if (t && t.role && t.content) messages.push({ role: t.role, content: t.content }); }
// vision: if he sent a photo, fetch it and attach to the latest user turn so she can actually see it
const sd = $('Set Delay').first().json || {};
const pf = sd.photo_file_id;
if (pf) {
  let url = null;
  try {
    const r = await this.helpers.httpRequest({ method: 'GET', url: 'https://api.telegram.org/bot__BOT_TOKEN__/getFile', qs: { file_id: pf }, json: true });
    const fpth = r && r.result && r.result.file_path;
    if (fpth) url = 'https://api.telegram.org/file/bot__BOT_TOKEN__/' + fpth;
  } catch (e) { url = null; }
  if (url) {
    const capt = (sd.msg && sd.msg[0] !== '[' && sd.msg[0] !== '(') ? sd.msg : '';
    const vtext = capt ? (capt + ' (he sent this with a photo, react to the photo too)') : 'he just sent you this photo. react to it naturally in your voice, like a real girl reacting to a pic he sent. say something specific about what is actually in it.';
    for (let i = messages.length - 1; i >= 0; i--) {
      if (messages[i].role === 'user') { messages[i] = { role: 'user', content: [ { type: 'text', text: vtext }, { type: 'image_url', image_url: { url: url } } ] }; break; }
    }
  }
}
const count = ctx.count || 0;
return [{ json: { messages: messages, model: model, fan_id: ctx.fan_id, bot_id: ctx.bot_id, count: count, archetype: archetype, spark: (cls.spark === true), convo_health: (cls.convo_health || 'healthy') } }];

const d = $json || {};
let reply = '';
try { reply = (d.choices && d.choices[0] && d.choices[0].message && d.choices[0].message.content) ? d.choices[0].message.content : ''; } catch (e) { reply = ''; }
reply = (reply || '').trim();
const dq = String.fromCharCode(34);
if (reply.length > 1 && reply.charAt(0) === dq && reply.charAt(reply.length - 1) === dq) { reply = reply.slice(1, -1).trim(); }
const allowed = ['\u{1F60F}', '\u{1F92D}', '\u{1F90D}', '\u{1F440}'];
let ec = 0;
reply = reply.replace(/\p{Extended_Pictographic}/gu, function (m) { if (allowed.indexOf(m) === -1) return ''; ec++; return ec > 1 ? '' : m; });
reply = reply.replace(/[\u{FE0F}\u{200D}]/gu, '');
reply = reply.replace(/\s*[\u2014\u2013]\s*/g, ' ').replace(/\s+-\s+/g, ' ');
reply = reply.toLowerCase().replace(/[ \t]{2,}/g, ' ').trim();
if (!reply) { reply = 'hey you'; }
const bm = $('Build Messages').first().json;
return [{ json: { reply: reply, fan_id: bm.fan_id, bot_id: bm.bot_id, spark: (bm.spark === true) } }];

const ctx = $('DB: ingest').first().json || {};
const fr = $('Format Reply').first().json || {};
const recent = Array.isArray(ctx.recent) ? ctx.recent : [];
const lines = recent.map(function (t) { return (t.role === 'user' ? 'him: ' : 'her: ') + t.content; });
lines.push('her: ' + (fr.reply || ''));
const convo = lines.join('\n');
const prevNote = (ctx.summary && ctx.summary.length) ? ctx.summary : 'none';
const prevProfile = (ctx.profile && typeof ctx.profile === 'object' && !Array.isArray(ctx.profile)) ? ctx.profile : {};
const sys = [
'you are an expert retention strategist for a creator\u2019s private telegram. candace chats one on one with men to make them fall for her and keep coming back. she is NOT selling anything here. you read the conversation and produce an honest, accurate, unsentimental read of THIS man: how attached and hooked he is, where he is in the relationship, his type, and the exact technique to keep him coming back. you are accurate, not optimistic. output one json object only.',
