'technique by type: provider or baller, make him feel like the man and needed. submissive, dominate and make him earn your attention. lonely or romantic, build emotional intimacy and girlfriend energy. tire_kicker, do not over invest, keep light.'
].join('\n');
const usr = 'previous notes on him: ' + prevNote + '\nprevious structured profile (merge into it, do not lose these): ' + JSON.stringify(prevProfile) + '\nconversation so far (oldest first):\n' + convo + '\noutput the json now.';
return [{ json: { profileMessages: [{ role: 'system', content: sys }, { role: 'user', content: usr }], fan_id: ctx.fan_id, reply: (fr.reply || '') } }];

